package com.example.secondphone.controller;
import java.util.List;import org.springframework.http.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import com.example.secondphone.dto.*;import com.example.secondphone.service.TradeInService;import io.swagger.v3.oas.annotations.tags.Tag;import jakarta.validation.Valid;
@RestController @RequestMapping("/api/member/trade-ins") @Tag(name="會員收購",description="會員提交、查詢與回覆舊機報價")
public class TradeInController{private final TradeInService service;public TradeInController(TradeInService service){this.service=service;}@PostMapping public ResponseEntity<TradeInResponse> submit(Authentication auth,@Valid @RequestBody TradeInRequest q){return ResponseEntity.status(HttpStatus.CREATED).body(service.submit(auth.getName(),q));}@GetMapping public List<TradeInResponse> list(Authentication auth){return service.memberList(auth.getName());}@GetMapping("/{id}") public TradeInResponse detail(Authentication auth,@PathVariable Long id){return service.memberDetail(auth.getName(),id);}@PostMapping("/{id}/accept") public TradeInResponse accept(Authentication auth,@PathVariable Long id){return service.respond(auth.getName(),id,true);}@PostMapping("/{id}/reject") public TradeInResponse reject(Authentication auth,@PathVariable Long id){return service.respond(auth.getName(),id,false);}}
